/**
 * Loads secrets from BuildConfig fields, which should be injected at build time
 * from environment variables or a secret manager (e.g., via gradle properties,
 * CI/CD secrets, or a vault).
 *
 * In build.gradle.kts:
 *   android {
 *       defaultConfig {
 *           buildConfigField("String", "FACEBOOK_APP_ID", "\"${System.getenv("FACEBOOK_APP_ID") ?: ""}\"")
 *           buildConfigField("String", "FACEBOOK_APP_SECRET", "\"${System.getenv("FACEBOOK_APP_SECRET") ?: ""}\"")
 *           buildConfigField("String", "GOOGLE_CLIENT_ID", "\"${System.getenv("GOOGLE_CLIENT_ID") ?: ""}\"")
 *           buildConfigField("String", "GOOGLE_CLIENT_SECRET", "\"${System.getenv("GOOGLE_CLIENT_SECRET") ?: ""}\"")
 *       }
 *   }
 */
class BuildConfigSecretProvider : SecretProvider {

    override fun getFacebookAppId(): String {
        val value = getEnvOrBuildConfig("FACEBOOK_APP_ID")
        require(value.isNotBlank()) {
            "FACEBOOK_APP_ID not configured. Set it as an environment variable or in your secret manager."
        }
        return value
    }

    override fun getFacebookAppSecret(): String {
        val value = getEnvOrBuildConfig("FACEBOOK_APP_SECRET")
        require(value.isNotBlank()) {
            "FACEBOOK_APP_SECRET not configured. Set it as an environment variable or in your secret manager."
        }
        return value
    }

    override fun getGoogleClientId(): String {
        val value = getEnvOrBuildConfig("GOOGLE_CLIENT_ID")
        require(value.isNotBlank()) {
            "GOOGLE_CLIENT_ID not configured. Set it as an environment variable or in your secret manager."
        }
        return value
    }

    override fun getGoogleClientSecret(): String {
        val value = getEnvOrBuildConfig("GOOGLE_CLIENT_SECRET")
        require(value.isNotBlank()) {
            "GOOGLE_CLIENT_SECRET not configured. Set it as an environment variable or in your secret manager."
        }
        return value
    }

    private fun getEnvOrBuildConfig(key: String): String {
        // First try environment variable (useful for server-side or testing)
        System.getenv(key)?.takeIf { it.isNotBlank() }?.let { return it }

        // Then try BuildConfig via reflection (injected at build time from env vars)
        try {
            val buildConfigClass = Class.forName("com.example.sociallogin.BuildConfig")
            val field = buildConfigClass.getField(key)
            val value = field.get(null) as? String
            if (!value.isNullOrBlank()) return value
        } catch (_: Exception) {
            // BuildConfig field not found
        }

        return ""
    }
}

// --- Secure Token Storage ---

/**
 * Stores authentication tokens securely using EncryptedSharedPreferences
 * backed by Android Keystore.
 *
 * NEVER stores raw passwords. Only stores OAuth tokens which can be revoked.
 */
class SecureTokenStorage(context: Context) {

    companion object {
        private const val PREFS_FILE_NAME = "secure_auth_tokens"
        private const val KEY_ACCESS_TOKEN = "access_token"
        private const val KEY_REFRESH_TOKEN = "refresh_token"
        private const val KEY_TOKEN_PROVIDER = "token_provider"
        private const val KEY_TOKEN_EXPIRY = "token_expiry"
    }

    private val masterKey: MasterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .setKeyGenParameterSpec(
            KeyGenParameterSpec.Builder(
                MasterKey.DEFAULT_MASTER_KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .build()
        )
        .build()

    private val encryptedPrefs = EncryptedSharedPreferences.create(
        context,
        PREFS_FILE_NAME,
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun storeTokens(
        provider: AuthProvider,
        accessToken: String,
        refreshToken: String? = null,
        expiryTimestamp: Long = 0L
    ) {
        encryptedPrefs.edit().apply {
            putString(KEY_ACCESS_TOKEN, accessToken)
            putString(KEY_TOKEN_PROVIDER, provider.name)
            putLong(KEY_TOKEN_EXPIRY, expiryTimestamp)
            if (refreshToken != null) {
                putString(KEY_REFRESH_TOKEN, refreshToken)
            }
            apply()
        }
    }

    fun getAccessToken(): String? {
        val expiry = encryptedPrefs.getLong(KEY_TOKEN_EXPIRY, 0L)
        if (expiry > 0 && System.currentTimeMillis() > expiry) {
            // Token expired, clear it
            clearTokens()
            return null
        }
        return encryptedPrefs.getString(KEY_ACCESS_TOKEN, null)
    }

    fun getRefreshToken(): String? {
        return encryptedPrefs.getString(KEY_REFRESH_TOKEN, null)
    }

    fun getProvider(): AuthProvider? {
        val providerName = encryptedPrefs.getString(KEY_TOKEN_PROVIDER, null) ?: return null
        return try {
            AuthProvider.valueOf(providerName)
        } catch (_: IllegalArgumentException) {
            null
        }
    }

    fun isLoggedIn(): Boolean {
        return getAccessToken() != null
    }

    fun clearTokens() {
        encryptedPrefs.edit().clear().apply()
    }
}

// --- Auth Models ---

enum class AuthProvider {
    FACEBOOK,
    GOOGLE
}

data class AuthResult(
    val success: Boolean,
    val provider: AuthProvider,
    val accessToken: String? = null,
    val userId: String? = null,
    val email: String? = null,
    val displayName: String? = null,
    val errorMessage: String? = null
)

data class UserProfile(
    val id: String,
    val email: String?,
    val displayName: String?,
    val profilePictureUrl: String?,
    val provider: AuthProvider
)

// --- OAuth Configuration ---

data class OAuthConfig(
    val clientId: String,
    val clientSecret: String,
    val authorizationUrl: String,
    val tokenUrl: String,
    val redirectUri: String,
    val scopes: List<String>
)

// --- Social Login Manager ---

class SocialLoginManager private constructor(
    private val context: Context,
    private val secretProvider: SecretProvider,
    private val tokenStorage: SecureTokenStorage
) {

    companion object {
        @Volatile
        private var instance: SocialLoginManager? = null

        fun initialize(
            context: Context,
            secretProvider: SecretProvider = BuildConfigSecretProvider()
        ): SocialLoginManager {
            return instance ?: synchronized(this) {
                instance ?: SocialLoginManager(
                    context.applicationContext,
                    secretProvider,
                    SecureTokenStorage(context.applicationContext)
                ).also { instance = it }
            }
        }

        fun getInstance(): SocialLoginManager {
            return instance
                ?: throw IllegalStateException("SocialLoginManager not initialized. Call initialize() first.")
        }
    }

    private fun getFacebookOAuthConfig(): OAuthConfig {
        return OAuthConfig(
            clientId = secretProvider.getFacebookAppId(),
            clientSecret = secretProvider.getFacebookAppSecret(),
            authorizationUrl = "https://www.facebook.com/v18.0/dialog/oauth",
            tokenUrl = "https://graph.facebook.com/v18.0/oauth/access_token",
            redirectUri = "https://localhost/callback/facebook",
            scopes = listOf("email", "public_profile")
        )
    }

    private fun getGoogleOAuthConfig(): OAuthConfig {
        return OAuthConfig(
            clientId = secretProvider.getGoogleClientId(),
            clientSecret = secretProvider.getGoogleClientSecret(),
            authorizationUrl = "https://accounts.google.com/o/oauth2/v2/auth",
            tokenUrl = "https://oauth2.googleapis.com/token",
            redirectUri = "https://localhost/callback/google",
            scopes = listOf("openid", "email", "profile")
        )
    }

    /**
     * Builds the authorization URL for the given provider.
     * The user should be redirected to this URL in a browser/WebView.
     */
    fun getAuthorizationUrl(provider: AuthProvider, state: String): String {
        val config = when (provider) {
            AuthProvider.FACEBOOK -> getFacebookOAuthConfig()
            AuthProvider.GOOGLE -> getGoogleOAuthConfig()
        }

        val scopeString = config.scopes.joinToString(" ")

        return buildString {
            append(config.authorizationUrl)
            append("?client_id=${config.clientId}")
            append("&redirect_uri=${config.redirectUri}")
            append("&response_type=code")
            append("&scope=$scopeString")
            append("&state=$state")
            if (provider == AuthProvider.GOOGLE) {
                append("&access_type=offline")
                append("&prompt=consent")
            }
        }
    }

    /**
     * Exchanges an authorization code for tokens.
     * This should be called after the user is redirected back with an auth code.
     *
     * In production, the token exchange (which requires the client secret)
     * should happen on your backend server, not on the client device.
     */
    suspend fun exchangeCodeForToken(
        provider: AuthProvider,
        authorizationCode: String
    ): AuthResult {
        val config = when (provider) {
            AuthProvider.FACEBOOK -> getFacebookOAuthConfig()
            AuthProvider.GOOGLE -> getGoogleOAuthConfig()
        }

        return try {
            // NOTE: In a production app, this exchange should happen on your
            // backend server to avoid exposing the client secret on the device.
            // The client sends the auth code to your server, and your server
            // exchanges it for tokens using the client secret.
            val tokenResponse = performTokenExchange(config, authorizationCode)

            // Store tokens securely
            tokenStorage.storeTokens(
                provider = provider,
                accessToken = tokenResponse.accessToken,
                refreshToken = tokenResponse.refreshToken,
                expiryTimestamp = System.currentTimeMillis() + (tokenResponse.expiresIn * 1000L)
            )

            // Fetch user profile
            val profile = fetchUserProfile(provider, tokenResponse.accessToken)

            AuthResult(
                success = true,
                provider = provider,
                accessToken = tokenResponse.accessToken,
                userId = profile?.id,
                email = profile?.email,
                displayName = profile?.displayName
            )
        } catch (e: Exception) {
            // Never log tokens or secrets
            Log.e("SocialLogin", "Authentication failed for provider: ${provider.name}")
            AuthResult(
                success = false,
                provider = provider,
                errorMessage = "Authentication failed. Please try again."
            )
        }
    }

    /**
     * Handles the callback from the OAuth redirect.
     */
    suspend fun handleCallback(
        provider: AuthProvider,
        callbackUrl: String,
        expectedState: String
    ): AuthResult {
        return try {
            val uri = android.net.Uri.parse(callbackUrl)

            // Verify state parameter to prevent CSRF
            val returnedState = uri.getQueryParameter("state")
            if (returnedState != expectedState) {
                return AuthResult(
                    success = false,
                    provider = provider,
                    errorMessage = "Invalid state parameter. Possible CSRF attack."
                )
            }

            // Check for errors
            val error = uri.getQueryParameter("error")
            if (error != null) {
                val errorDescription = uri.getQueryParameter("error_description") ?: "Unknown error"
                return AuthResult(
                    success = false,
                    provider = provider,
                    errorMessage = errorDescription
                )
            }

            val code = uri.getQueryParameter("code")
                ?: return AuthResult(
                    success = false,
                    provider = provider,
                    errorMessage = "No authorization code received."
                )

            exchangeCodeForToken(provider, code)
        } catch (e: Exception) {
            Log.e("SocialLogin", "Callback handling failed for provider: ${provider.name}")
            AuthResult(
                success = false,
                provider = provider,
                errorMessage = "Failed to process authentication callback."
            )
        }
    }

    fun isLoggedIn(): Boolean = tokenStorage.isLoggedIn()

    fun getCurrentProvider(): AuthProvider? = tokenStorage.getProvider()

    fun logout() {
        tokenStorage.clearTokens()
    }

    fun getStoredAccessToken(): String? = tokenStorage.getAccessToken()

    // --- Internal token exchange ---

    private data class TokenResponse(
        val accessToken: String,
        val refreshToken: String? = null,
        val expiresIn: Long = 3600,
        val tokenType: String = "Bearer"
    )

    /**
     * Performs the OAuth token exchange.
     *
     * IMPORTANT: In production, move this to your backend server so the
     * client_secret never resides on the device. The mobile app should
     * send the authorization code to your server endpoint, which then
     * performs the exchange and returns only the access token.
     */
    private suspend fun performTokenExchange(
        config: OAuthConfig,
        authorizationCode: String
    ): TokenResponse {
        val url = java.net.URL(config.tokenUrl)
        val connection = url.openConnection() as java.net.HttpURLConnection

        try {
            connection.requestMethod = "POST"
            connection.doOutput = true
            connection.setRequestProperty("Content-Type", "application/x-www-form-urlencoded")
            connection.connectTimeout = 15000
            connection.readTimeout = 15000

            val postData = buildString {
                append("grant_type=authorization_code")
                append("&code=$authorizationCode")
                append("&client_id=${config.clientId}")
                append("&client_secret=${config.clientSecret}")
                append("&redirect_uri=${config.redirectUri}")
            }

            connection.outputStream.use { os ->
                os.write(postData.toByteArray(Charsets.UTF_8))
            }

            val responseCode = connection.responseCode
            if (responseCode != 200) {
                throw RuntimeException("Token exchange failed with HTTP $responseCode")
            }

            val responseBody = connection.inputStream.bufferedReader().use { it.readText() }
            return parseTokenResponse(responseBody)
        } finally {
            connection.disconnect()
        }
    }

    private fun parseTokenResponse(jsonString: String): TokenResponse {
        // Simple JSON parsing without external dependencies
        val accessToken = extractJsonString(jsonString, "access_token")
            ?: throw RuntimeException("No access_token in response")
        val refreshToken = extractJsonString(jsonString, "refresh_token")
        val expiresIn = extractJsonLong(jsonString, "expires_in") ?: 3600L
        val tokenType = extractJsonString(jsonString, "token_type") ?: "Bearer"

        return TokenResponse(
            accessToken = accessToken,
            refreshToken = refreshToken,
            expiresIn = expiresIn,
            tokenType = tokenType
        )
    }

    private suspend fun fetchUserProfile(
        provider: AuthProvider,
        accessToken: String
    ): UserProfile? {
        return try {
            when (provider) {
                AuthProvider.FACEBOOK -> fetchFacebookProfile(accessToken)
                AuthProvider.GOOGLE -> fetchGoogleProfile(accessToken)
            }
        } catch (e: Exception) {
            Log.e("SocialLogin", "Failed to fetch user profile for ${provider.name}")
            null
        }
    }

    private suspend fun fetchFacebookProfile(accessToken: String): UserProfile {
        val url = java.net.URL(
            "https://graph.facebook.com/me?fields=id,name,email,picture.type(large)&access_token=$accessToken"
        )
        val responseBody = fetchUrl(url)

        return UserProfile(
            id = extractJsonString(responseBody, "id") ?: "",
            email = extractJsonString(responseBody, "email"),
            displayName = extractJsonString(responseBody, "name"),
            profilePictureUrl = null, // Would need nested JSON parsing for picture URL
            provider = AuthProvider.FACEBOOK
        )
    }

    private suspend fun fetchGoogleProfile(accessToken: String): UserProfile {
        val url = java.net.URL("https://www.googleapis.com/oauth2/v2/userinfo")
        val connection = url.openConnection() as java.net.HttpURLConnection
        connection.setRequestProperty("Authorization", "Bearer $accessToken")
        connection.connectTimeout = 15000
        connection.readTimeout = 15000

        try {
            val responseBody = connection.inputStream.bufferedReader().use { it.readText() }

            return UserProfile(
                id = extractJsonString(responseBody, "id") ?: "",
                email = extractJsonString(responseBody, "email"),
                displayName = extractJsonString(responseBody, "name"),
                profilePictureUrl = extractJsonString(responseBody, "picture"),
                provider = AuthProvider.GOOGLE
            )
        } finally {
            connection.disconnect()
        }
    }

    private fun fetchUrl(url: java.net.URL): String {
        val connection = url.openConnection() as java.net.HttpURLConnection
        connection.connectTimeout = 15000
        connection.readTimeout = 15000
        try {
            return connection.inputStream.bufferedReader().use { it.readText() }
        } finally {
            connection.disconnect()
        }
    }

    // Simple JSON helpers (in production, use a proper JSON library like Moshi or kotlinx.serialization)
    private fun extractJsonString(json: String, key: String): String? {
        val pattern = "\"$key\"\\s*:\\s*\"([^\"]*)\""
        val regex = Regex(pattern)
        return regex.find(json)?.groupValues?.get(1)
    }

    private fun extractJsonLong(json: String, key: String): Long? {
        val pattern = "\"$key\"\\s*:\\s*(\\d+)"
        val regex = Regex(pattern)
        return regex.find(json)?.groupValues?.get(1)?.toLongOrNull()
    }
}

// --- CSRF State Manager ---

/**
 * Generates and validates CSRF state tokens for OAuth flows.
 * State tokens are stored in encrypted storage.
 */
class OAuthStateManager(context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val encryptedPrefs = EncryptedSharedPreferences.create(
        context,
        "oauth_state_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun generateState(): String {
        val state = java.util.UUID.randomUUID().toString()
        encryptedPrefs.edit()
            .putString("oauth_state", state)
            .putLong("oauth_state_created", System.currentTimeMillis())
            .apply()
        return state
    }

    fun validateAndConsumeState(state: String): Boolean {
        val storedState = encryptedPrefs.getString("oauth_state", null)
        val createdAt = encryptedPrefs.getLong("oauth_state_created", 0L)

        // Clear the state after validation (one-time use)
        encryptedPrefs.edit()
            .remove("oauth_state")
            .remove("oauth_state_created")
            .apply()

        if (storedState == null || storedState != state) {
            return false
        }

        // State tokens expire after 10 minutes
        val tenMinutesMs = 10 * 60 * 1000L
        if (System.currentTimeMillis() - createdAt > tenMinutesMs) {
            return false
        }

        return true
    }
}